-- Spec 008: telemetría cliente (FR-040). Ejecutar en esquema GESTIONRRHH antes de usar POST /api/telemetry/client.
-- Ajustar IDENTITY según estándar local si no se usa GENERATED BY DEFAULT AS IDENTITY.

CREATE TABLE GESTIONRRHH.CLIENT_TELEMETRY (
    ID              NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    CATEGORY        VARCHAR2(120 CHAR) NOT NULL,
    PAYLOAD_JSON    CLOB,
    IP              VARCHAR2(128 CHAR),
    USER_AGENT      VARCHAR2(512 CHAR),
    CREATED_AT      TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
